// Parses the normalized JSON output from the previous node and splits it
// into individual items, one per event, so downstream nodes (storage,
// risk scoring) can process them independently.
const stdout = $input.first().json.stdout;
let events;
try {
  events = JSON.parse(stdout);
} catch (e) {
  throw new Error('Failed to parse normalized ACLED output as JSON: ' + e.message);
}
return events.map(event => ({ json: event }));
